import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { coursesService } from '../../services/courses';
import { authService } from '../../services/auth';
import './Dashboard.css';

const InstructorDashboard = () => {
  const navigate = useNavigate();
  const [courses, setCourses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showCreateForm, setShowCreateForm] = useState(false);
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    price: '',
    image: null,
  });
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState('');

  const user = authService.getUserFromStorage(); //newwww

  useEffect(() => {
    loadCourses();
  }, []);

  const loadCourses = async () => {
    try {
      setLoading(true);
      const user = authService.getUserFromStorage();
      const data = await coursesService.getAll({ instructor: user?.id });
      const myCourses = Array.isArray(data) 
        ? data
        : (data.results || []);
      setCourses(myCourses);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (e) => {
    if (e.target.name === 'image') {
      setFormData({ ...formData, image: e.target.files[0] });
    } else {
      setFormData({ ...formData, [e.target.name]: e.target.value });
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSubmitting(true);

    try {
      await coursesService.create(formData);
      setShowCreateForm(false);
      setFormData({ title: '', description: '', price: '', image: null });
      loadCourses();
    } catch (err) {
      const errorData = err.response?.data;
      if (typeof errorData === 'object') {
        const errorMessages = Object.values(errorData).flat();
        setError(errorMessages.join(', '));
      } else {
        setError('Failed to create course');
      }
    } finally {
      setSubmitting(false);
    }
  };

  if (loading) {
    return <div className="loading">Loading dashboard...</div>;
  }

  return (
    <div className="dashboard">
      <div className="dashboard-header">
        <h1>Instructor Dashboard</h1>
        <button
          onClick={() => setShowCreateForm(!showCreateForm)}
          className="btn btn-primary"
        >
          {showCreateForm ? 'Cancel' : 'Create New Course'}
        </button>
          {/* 👇 جديد: زر مراجعة الكورسات (لو المستخدم Admin) */}
        {user && user.is_staff && (
          <button
            onClick={() => navigate('/admin/courses')}
            className="btn btn-secondary"
            style={{ marginLeft: '10px' }}
          >
           Check
          </button>
        )}
      </div>

      {showCreateForm && (
        <div className="create-course-form">
          <h2>Create New Course</h2>
          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label>Title *</label>
              <input
                type="text"
                name="title"
                value={formData.title}
                onChange={handleChange}
                required
              />
            </div>
            <div className="form-group">
              <label>Description *</label>
              <textarea
                name="description"
                value={formData.description}
                onChange={handleChange}
                required
              />
            </div>
            <div className="form-group">
              <label>Price *</label>
              <input
                type="number"
                name="price"
                step="0.01"
                min="0"
                value={formData.price}
                onChange={handleChange}
                required
              />
            </div>
            <div className="form-group">
              <label>Course Image</label>
              <input
                type="file"
                name="image"
                accept="image/*"
                onChange={handleChange}
              />
            </div>
            {error && <div className="error-message">{error}</div>}
            <button
              type="submit"
              className="btn btn-primary"
              disabled={submitting}
            >
              {submitting ? 'Creating...' : 'Create Course'}
            </button>
          </form>
        </div>
      )}

      <h2>My Courses</h2>
      {courses.length === 0 ? (
        <div className="empty-state">
          <p>You haven't created any courses yet.</p>
        </div>
      ) : (
        <div className="courses-grid">
          {courses.map((course) => (
            <div key={course.id} className="course-card">
              <div
                onClick={() => navigate(`/courses/${course.id}`)}
                style={{ cursor: 'pointer' }}
              >
                {course.image_url ? (
                  <img src={course.image_url} alt={course.title} />
                ) : (
                  <div className="course-image-placeholder">No Image</div>
                )}
                <div className="course-info">
                  <h3>{course.title}</h3>
                  <p className="course-status">
                    Status:{' '}
                    {course.is_approved ? (
                      <span className="status-approved">Approved</span>
                    ) : (
                      <span className="status-pending">Pending Approval</span>
                    )}
                  </p>
                  <span className="course-price">
                    ${parseFloat(course.price).toFixed(2)}
                  </span>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default InstructorDashboard;
